import React, { useEffect, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";

function PredictionHistoryPage() {
  const [history, setHistory] = useState([]);
  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    fetchHistory();
    // eslint-disable-next-line
  }, []);

  const fetchHistory = async () => {
    try {
      if (!user?.email) return;
      const res = await API.get(`/history/${user.email}`);
      setHistory(res.data);
    } catch (error) {
      console.error("Failed to load prediction history");
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="patient" />

      <div className="main-content">
        <Navbar
          title="Prediction History"
          subtitle="View all your previous AI disease predictions"
        />

        <div className="row g-4">
          {history.length === 0 ? (
            <div className="col-12">
              <div className="empty-card">
                <h4>No Prediction History Found</h4>
                <p>Your previous reports will appear here.</p>
              </div>
            </div>
          ) : (
            history.map((item) => (
              <div className="col-md-6 col-lg-4" key={item.id}>
                <div className="history-card">
                  <h5>{item.patient_name}</h5>
                  <p>
                    <strong>Disease:</strong> {item.predicted_disease}
                  </p>
                  <p>
                    <strong>Doctor:</strong> {item.predicted_doctor}
                  </p>
                  <p>
                    <strong>Specialization:</strong> {item.specialization}
                  </p>
                  <p>
                    <strong>Confidence:</strong> {item.confidence}%
                  </p>
                  <p className="history-date">{item.created_at}</p>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

export default PredictionHistoryPage;
